import subprocess

def run_command(command):
    process = subprocess.Popen(command, shell=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    out, err = process.communicate()
    if process.returncode != 0:
        raise ValueError(f'Error occurred while executing command:\n {command}\n Output: {out}\n Error: {err}')

run_command('pip install --upgrade -r requirements.txt --no-hash-check')